<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model;
class ToolRequest extends Model { protected $guarded = []; protected function casts(): array { return ['requested_at'=>'datetime:Y-m-d H:i:s','accepted_at'=>'datetime:Y-m-d H:i:s','rejected_at'=>'datetime:Y-m-d H:i:s','en_route_at'=>'datetime:Y-m-d H:i:s','delivered_at'=>'datetime:Y-m-d H:i:s','picked_up_at'=>'datetime:Y-m-d H:i:s','ready_for_pickup_at'=>'datetime:Y-m-d H:i:s','finalized_at'=>'datetime:Y-m-d H:i:s','cancelled_at'=>'datetime:Y-m-d H:i:s']; } public function technician(){ return $this->belongsTo(User::class, 'technician_id'); } public function driver(){ return $this->belongsTo(User::class, 'driver_id'); } public function vehicle(){ return $this->belongsTo(Vehicle::class); } public function items(){ return $this->hasMany(ToolRequestItem::class); } public function histories(){ return $this->hasMany(ToolRequestStatusHistory::class); } public function chat(){ return $this->hasOne(Chat::class); } }
